/* 代码块折叠样式 */
.highlight {
    position: relative;
    max-height: 300px;           /* 默认只显示 300px 高度，超出部分隐藏 */
    overflow: hidden;
    transition: max-height 0.3s ease;
}

.highlight.expanded {
    max-height: none;            /* 展开时恢复完整高度 */
}

.highlight .fold-toggle {
    position: absolute;
    bottom: 8px;
    right: 12px;
    background: rgba(0, 123, 255, 0.9);
    color: #fff;
    border: none;
    padding: 4px 14px;
    border-radius: 4px;
    font-size: 13px;
    cursor: pointer;
    z-index: 10;
    box-shadow: 0 2px 6px rgba(0,0,0,0.2);
}

.highlight .fold-toggle:hover {
    background: rgba(0, 86, 179, 0.95);
}

/* 如果代码块高度不足 300px，不显示折叠按钮 */
.highlight.short .fold-toggle {
    display: none;
}

/* 代码块背景色 - 覆盖 Icarus 默认 */
figure.highlight,
.highlight-body,
figure.highlight .highlight-body {
    background-color: #2d2d2d !important;
}

/* 如果行号区域背景也要改 */
figure.highlight .gutter,
figure.highlight .gutter .line {
    background-color: #1e1e1e !important;
}

/* 代码区域背景（覆盖 .code td 的背景） */
figure.highlight .code,
figure.highlight .code .line {
    background-color: #2d2d2d !important;
}

/* 表格本身背景 */
figure.highlight table,
figure.highlight tbody,
figure.highlight tr {
    background-color: transparent !important;
}

