                    ld exp = 0.0;
                    for (int da = 0; da < 3; ++da) {
                        for (int db = 0; db < 3; ++db) {
                            ca[da]++; cb[db]++;
                            int nia = id[ca], nib = id[cb];
                            int ns = nia * 10 + nib;
                            exp += dp[k-1][ns];
                            ca[da]--; cb[db]--;
                        }
                    }
                    exp /= 9.0;
                    val += exp;
                    ca[a]++; cb[b]++;
                    worst = min(worst, val);
                }
                best = max(best, worst);
            }
            dp[k][s] = best;
        }
    }
    ld rho = 0.0;
    for (int s = 0; s < 100; ++s) rho += (dp[KMAX][s] - dp[KMAX-1][s]);
    rho /= 100.0;
    ld v[100];
    for (int s = 0; s < 100; ++s)
        v[s] = dp[KMAX][s] - (ld)KMAX * rho;
    int T;
    cin >> T;
    while (T--) {
        i64 k;
        string a, b;
        cin >> k >> a >> b;
        array<int,3> ca = {0,0,0}, cb = {0,0,0};
        for (char c : a) {
            if (c == 'R') ca[0]++;
            else if (c == 'S') ca[1]++;
            else ca[2]++;
        }
        for (char c : b) {
            if (c == 'R') cb[0]++;
            else if (c == 'S') cb[1]++;
            else cb[2]++;
        }
        int s = id[ca] * 10 + id[cb];
        ld ans;
        if (k <= KMAX) {
            ans = dp[k][s];
        } else {
            ans = (ld)k * rho + v[s];
        }
        cout << fixed << setprecision(12) << ans << '\n';
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t = 1;
    //cin >> t
    while(t--) solve();
    return 0;
}
