## 4. 最大子段和

### 问题描述：
给定一个整数数组，求**连续子数组**的最大和。

### 转移方程：
```cpp
dp[i] = max(a[i],dp[i - 1] + a[i]);
```

### 代码模板：
```cpp
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

void solve() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for(int i = 0;i < n;++i) cin >> nums[i];
    int cur = nums[0]; // 以第一个元素结尾的最大和
    int ans = cur; // 全局最大和
    for(int i = 1;i < n;++i) {
        cur = max(cur + nums[i],nums[i]); // 以nums[i]结尾的最大和
        ans = max(ans,cur); // 更新全局最大和
    }
    cout << ans << "\n";
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    cout.tie(nullptr);
    int t = 1;
    //cin >> t;
    while(t--) solve();
    return 0;
}
```

