## A*算法（K短路）

### 适用场景
**·** 求第 K 短路径
**·** 启发式搜索
**·** 核心公式：`f(n) = g(n) + h(n)`
    · `g(n)`：从起点到当前点的实际距离
    · `h(n)`：从当前点到终点的估计距离（通常为反向图的最短路）

### 核心思想
用优先队列按`f(n)`排序，优先扩展估值更小的点。当终点第`K`次出队时，即为第`K`短路。

### 代码模板
```cpp
#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
typedef pair<ll, int> P;
typedef pair<ll, pair<ll, int>> P3; // {f, {g, u}}

const ll INF = 4e18;

// 预处理反向图最短路
vector<ll> dijkstra(int n, vector<vector<pair<int, ll>>>& g, int s) {
    vector<ll> dist(n + 1, INF);
    priority_queue<P, vector<P>, greater<P>> pq;
    dist[s] = 0;
    pq.push({0, s});
    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();
        if (d != dist[u]) continue;
        for (auto [v, w] : g[u]) {
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}

void solve() {
    int n, m, s, t, K;
    cin >> n >> m >> s >> t >> K;
    vector<vector<pair<int, ll>>> g(n + 1), rg(n + 1);
    for (int i = 0; i < m; ++i) {
        int u, v;
        ll w;
        cin >> u >> v >> w;
        g[u].push_back({v, w});
        rg[v].push_back({u, w}); // 反向图
    }
    vector<ll> h = dijkstra(n, rg, t);
    if (h[s] == INF) {
        cout << -1 << '\n';
        return;
    }
    priority_queue<P3, vector<P3>, greater<P3>> pq;
    pq.push({h[s], {0, s}});
    int cnt = 0;
    while (!pq.empty()) {
        auto [f, cur] = pq.top();
        pq.pop();
        auto [g_val, u] = cur;
        if (u == t) {
            ++cnt;
            if (cnt == K) {
                cout << g_val << '\n';
                return;
            }
        }
        for (auto [v, w] : g[u]) {
            ll ng = g_val + w;
            ll nf = ng + h[v];
            pq.push({nf, {ng, v}});
        }
    }
    cout << -1 << '\n';
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    solve();
    return 0;
}
```

