## 双向 Dijkstra

### 适用场景
**·** 起点和终点都确定的单源最短路
**·** 在网格图等大规模图中效果显著
**·** 搜索空间从 `O(b^d) 降至 O(b^{d/2})`

### 核心思想
从起点和终点**同时**进行 Dijkstra，每次扩展距离更小的一侧，直到两侧相遇。

### 代码模板
```cpp
#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
typedef pair<ll, int> P;

const ll INF = 4e18;

void solve() {
    int n, m, s, t;
    cin >> n >> m >> s >> t;
    vector<vector<pair<int, ll>>> g(n + 1);
    for (int i = 0; i < m; ++i) {
        int u, v;
        ll w;
        cin >> u >> v >> w;
        g[u].push_back({v, w});
        g[v].push_back({u, w});
    }
    vector<ll> dist_s(n + 1, INF), dist_t(n + 1, INF);
    vector<bool> vis_s(n + 1, false), vis_t(n + 1, false);
    priority_queue<P, vector<P>, greater<P>> pq_s, pq_t;
    dist_s[s] = 0;
    dist_t[t] = 0;
    pq_s.push({0, s});
    pq_t.push({0, t});
    ll ans = INF;
    while (!pq_s.empty() && !pq_t.empty()) {
        if (pq_s.top().first <= pq_t.top().first) {
            auto [d, u] = pq_s.top();
            pq_s.pop();
            if (vis_s[u]) continue;
            vis_s[u] = true;
            if (vis_t[u]) ans = min(ans, dist_s[u] + dist_t[u]);
            for (auto [v, w] : g[u]) {
                if (!vis_s[v] && dist_s[v] > dist_s[u] + w) {
                    dist_s[v] = dist_s[u] + w;
                    pq_s.push({dist_s[v], v});
                }
            }
        } 
        else {
            auto [d, u] = pq_t.top();
            pq_t.pop();
            if (vis_t[u]) continue;
            vis_t[u] = true;
            if (vis_s[u]) {
                ans = min(ans, dist_s[u] + dist_t[u]);
            }
            for (auto [v, w] : g[u]) {
                if (!vis_t[v] && dist_t[v] > dist_t[u] + w) {
                    dist_t[v] = dist_t[u] + w;
                    pq_t.push({dist_t[v], v});
                }
            }
        }
    }
    cout << (ans == INF ? -1 : ans) << '\n';
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    solve();
    return 0;
}
```

