## 问题描述

给定一个带权连通图，求一棵生成树，使得树上所有边的权值之和最小，称为**最小生成树（MST）**。

---

## Kruskal 算法

### 适用场景
- 边数较少的图（稀疏图）
- 时间复杂度：`O(E log E)`

### 核心思想
贪心 + 并查集：将所有边按权值从小到大排序，依次加入，若两端点不在同一连通块则合并。

### 代码模板
```cpp
#include <bits/stdc++.h>
using namespace std;

// ---------- 并查集（DSU） ----------
struct DSU {
    vector<int> parent, rnk; // parent[i] -> i的父节点, rnk[i] -> 以i为根的树的高度
    DSU(int n = 0) { init(n); }
    void init(int n) {
        parent.resize(n + 1);
        rnk.assign(n + 1, 0);
        for (int i = 1; i <= n; ++i) parent[i] = i;
    }
    int find(int x) {
        return parent[x] == x ? x : parent[x] = find(parent[x]); // 路径压缩
    }
    bool unite(int a, int b) {
        a = find(a), b = find(b);
        if (a == b) return false;
        if (rnk[a] < rnk[b]) swap(a, b);
        parent[b] = a;
        if (rnk[a] == rnk[b]) rnk[a]++;
        return true;
    }
};
// ---------- 边结构 ----------
struct Edge {
    int u, v, w;
    bool operator<(const Edge& other) const {
        return w < other.w;
    }
};

void solve() {
    int N, M;
    cin >> N >> M;
    vector<Edge> edges(M);
    for (int i = 0; i < M; ++i) {
        cin >> edges[i].u >> edges[i].v >> edges[i].w;
    }
    sort(edges.begin(), edges.end());
    DSU dsu(N);
    long long ans = 0;
    int cnt = 0;
    for (const Edge& e : edges) {
        if (dsu.unite(e.u, e.v)) {
            ans += e.w;
            cnt++;
            if (cnt == N - 1) break;
        }
    }
    if (cnt == N - 1) {
        cout << ans << '\n';
    } else {
        cout << "orz\n"; // 图不连通
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t = 1;
    // cin >> t;
    while (t--) solve();
    return 0;
}
```

