## 最小生成森林

### 适用场景
图不连通时，Kruskal 跑完得到的就是**最小生成森林**（每个连通块各自的最小生成树）。

### 核心思想
**·** 跑完 Kruskal 后，统计合并次数 cnt。
**·** 如果 cnt < N - 1，说明图不连通，剩余部分构成森林。
**·** 每个连通块内的边权之和即为该块的最小生成树权值。

### 代码模板
```cpp
#include <bits/stdc++.h>
using namespace std;

// ---------- 并查集（DSU） ----------
struct DSU {
    vector<int> parent, rnk; // parent[i] -> i的父节点, rnk[i] -> 以i为根的树高度
    DSU(int n = 0) { init(n); }
    void init(int n) {
        parent.resize(n + 1);
        rnk.assign(n + 1, 0);
        for (int i = 1; i <= n; ++i) parent[i] = i;
    }
    int find(int x) {
        return parent[x] == x ? x : parent[x] = find(parent[x]); // 路径压缩
    }
    bool unite(int a, int b) {
        a = find(a), b = find(b);
        if (a == b) return false;
        if (rnk[a] < rnk[b]) swap(a, b);
        parent[b] = a;
        if (rnk[a] == rnk[b]) rnk[a]++;
        return true;
    }
};


struct Edge {
    int u, v, w;
    bool operator<(const Edge& other) const {
        return w < other.w;
    }
};

void solve() {
    int N, M;
    cin >> N >> M;
    vector<Edge> edges(M);
    for (int i = 0; i < M; ++i) {
        cin >> edges[i].u >> edges[i].v >> edges[i].w;
    }
    sort(edges.begin(), edges.end());
    DSU dsu(N);
    vector<bool> used(M, false); // 记录每条边是否被选入森林
    long long total_weight = 0;  // 森林总权值
    int cnt = 0;                 // 已选边数
    for (int i = 0; i < M; ++i) {
        if (dsu.unite(edges[i].u, edges[i].v)) {
            used[i] = true;
            total_weight += edges[i].w;
            cnt++;
            // 注意：不 break！要跑完所有边，形成森林
        }
    }
    // 情况1：图连通 -> 输出最小生成树总权值
    if (cnt == N - 1) {
        cout << "连通，MST总权值 = " << total_weight << '\n';
    } 
    // 情况2：图不连通 -> 输出最小生成森林信息
    else {
        cout << "图不连通，最小生成森林由 " << (N - cnt) << " 个连通块组成\n";
        cout << "森林总权值 = " << total_weight << '\n';

        // 可选：输出每个连通块的信息
        // 统计每个连通块的根节点
        vector<vector<int>> components(N + 1);
        for (int i = 1; i <= N; ++i) {
            components[dsu.find(i)].push_back(i);
        }
        cout << "各连通块节点：\n";
        for (int i = 1; i <= N; ++i) {
            if (!components[i].empty()) {
                cout << "  块" << i << "：";
                for (int x : components[i]) cout << x << ' ';
                cout << '\n';
            }
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t = 1;
    // cin >> t; 
    while (t--) solve();
    return 0;
}
```

